function demoMode(){const samples=[["vk.com","Social network profile capture with messaging, media, telemetry, and PHP RPC signals."],["notion.so","Collaboration SaaS demo with workspaces, documents, auth, analytics, and API density."],["random SaaS","B2B dashboard demo with billing, users, roles, exports, and admin modules."],["shopify store","Commerce demo with catalog, cart, checkout, pixels, and third-party scripts."]];return el("div","grid",samples.map(([name,desc])=>el("div","card",[el("div","panel-body",[el("strong","",name),el("p","",desc),button("Open demo brief",()=>openDrawer(name+" sample report",objectCards(fakeSample(name,desc))))])])));}
function fakeSample(name,desc){return{target:name,summary:desc,modules:["Authentication","Profile","Analytics","Search","Media","Commerce"],api_density:"medium",tracking_intensity:"high",risk_language:["Passive Exposure Signal","Risk Pattern","Privacy Issue","Misconfiguration Hint"],note:"Synthetic commercial landing demo. No live scanning was performed."}}
function smartModules(){const groups=["Messaging","Profile","Commerce","Media","Notifications","Analytics","Search","Authentication"],map=new Map(groups.map(g=>[g,{name:g,raw:[],endpoints:[],telemetry:[],routes:[],risk:0,score:.45}]));const classify=text=>/message|chat|im|conversation|messenger/i.test(text)?"Messaging":/profile|user|friend|account|wall/i.test(text)?"Profile":/pay|billing|commerce|market|cart|shop|checkout|store/i.test(text)?"Commerce":/video|audio|photo|media|image|file|sticker/i.test(text)?"Media":/notif|push|bell/i.test(text)?"Notifications":/stat|track|telemetry|analytics|sentry|crash|metric|event/i.test(text)?"Analytics":/search|resolve|query/i.test(text)?"Search":/auth|login|oauth|token|session|captcha/i.test(text)?"Authentication":"Analytics";for(const m of DATA.module_graph.nodes||[]){const g=map.get(classify(m.id+" "+(m.sources||[]).join(" ")));g.raw.push(m);g.score=Math.max(g.score,Number(m.score||.4))}for(const e of endpointsFlat()){const g=map.get(classify(e.url+" "+e.category+" "+(e.entities||[]).join(" ")));g.endpoints.push(e);g.risk+=endpointRisk(e)>40?1:0;if(/stat|track|telemetry|event|crash/i.test(e.url+" "+e.category))g.telemetry.push(e)}for(const r of DATA.architecture.routing||[]){map.get(classify(r)).routes.push(r)}return Array.from(map.values()).filter(g=>g.raw.length||g.endpoints.length||g.routes.length||g.telemetry.length).sort((a,b)=>(b.endpoints.length+b.raw.length)-(a.endpoints.length+a.raw.length))}
