function commercialGraph(modules){const nodes=[],edges=[];for(const m of modules){nodes.push({id:m.name,type:"business module",score:m.score,sources:["business"]});for(const e of m.endpoints.slice(0,25)){const id=e.method+" "+e.url;nodes.push({id,type:"api module",score:e.confidence||.6,sources:[e.category||"api"]});edges.push({from:m.name,to:id,reason:"Module -> API"})}for(const t of m.telemetry.slice(0,12)){const id="Telemetry "+t.url;nodes.push({id,type:"telemetry",score:.65,sources:["telemetry"]});edges.push({from:m.name,to:id,reason:"Module -> Telemetry"})}for(const r of m.routes.slice(0,12)){const id="Route "+r;nodes.push({id,type:"route",score:.5,sources:["routes"]});edges.push({from:id,to:m.name,reason:"Route -> Module"})}}for(const e of DATA.module_graph.edges||[]){const a=moduleForText(e.from),b=moduleForText(e.to);if(a&&b&&a!==b)edges.push({from:a,to:b,reason:"Module -> Module"})}return{nodes:dedupeBy(nodes,n=>n.id),edges:dedupeBy(edges,e=>e.from+e.to+e.reason)}}
